INSERT INTO sale_transaction (
    complex_id, apt_dong, deal_amount, area, floor,
    deal_year, deal_month, deal_day, deal_type,
    sler_gbn, buyer_gbn, reg_date
) VALUES (
    #{complexId}, #{aptDong}, #{dealAmount}, #{area}, #{floor},
    #{dealYear}, #{dealMonth}, #{dealDay}, #{dealType},
    #{slerGbn}, #{buyerGbn}, #{regDate}
)

mapper.select:
SELECT COUNT(*) FROM sale_transaction
WHERE complex_id = #{complexId}
  AND deal_year  = #{dealYear}
  AND deal_month = #{dealMonth}
  AND deal_day   = #{dealDay}
  AND deal_amount = #{dealAmount}

SELECT * FROM sale_transaction
WHERE complex_id = #{complexId}
ORDER BY deal_year DESC, deal_month DESC, deal_day DESC
